static void diag_uart_init(void)
{
    /* Enable GPIOA clock (bit 0) and USART2 clock (bit 17 on APB1) */
    RCC_AHB1ENR |= (1U << 0);
    RCC_APB1ENR |= (1U << 17);

    /* Configure PA2 (TX) and PA3 (RX) as alternate function (AF7 = USART2) */
    GPIOA_MODER &= ~((3U << (2 * 2)) | (3U << (3 * 2)));
    GPIOA_MODER |=  ((2U << (2 * 2)) | (2U << (3 * 2)));

    GPIOA_AFRL &= ~((0xFU << (2 * 4)) | (0xFU << (3 * 4)));
    GPIOA_AFRL |=  ((7U << (2 * 4)) | (7U << (3 * 4)));

    /* Configure USART2: 115200 baud @ 16MHz APB1 clock */
    USART2_BRR = 0x008B;  /* 16000000 / 115200 ≈ 138.89 -> 8.6875 -> 0x008B */

    /* Enable USART, TX, RX */
    USART2_CR1 = 0;
    USART2_CR1 |= (1U << 13) | (1U << 3) | (1U << 2);
}

