static void diag_uart_send_uint32(uint32_t value)
{
    char buf[12];
    int i = 0;
    if (value == 0) {
        diag_uart_send_char('0');
        return;
    }
    while (value > 0 && i < 10) {
        buf[i++] = '0' + (value % 10);
        value /= 10;
    }
    for (int j = i - 1; j >= 0; j--) {
        diag_uart_send_char(buf[j]);
    }
}

