/* ============================================================
 * Utility: Parse hex string to uint32
 * ============================================================ */

static bool parse_hex(const char *str, uint32_t *out)
{
    if (!str || !out) return false;

    uint32_t result = 0;
    const char *p = str;

    /* Skip optional 0x prefix */
    if (p[0] == '0' && (p[1] == 'x' || p[1] == 'X')) {
        p += 2;
    }

    if (*p == '\0') return false;

    int count = 0;
    while (*p && count < 8) {
        char c = *p++;
        uint8_t nibble;
        if (c >= '0' && c <= '9')      nibble = c - '0';
        else if (c >= 'a' && c <= 'f') nibble = c - 'a' + 10;
        else if (c >= 'A' && c <= 'F') nibble = c - 'A' + 10;
        else return false;

        result = (result << 4) | nibble;
        count++;
    }

    *out = result;
    return true;
}

static bool parse_uint(const char *str, uint32_t *out)
{
    if (!str || !out) return false;

    /* Try hex first */
    if (str[0] == '0' && (str[1] == 'x' || str[1] == 'X')) {
        return parse_hex(str, out);
    }

    /* Decimal */
    uint32_t result = 0;
    const char *p = str;
    while (*p) {
        if (*p < '0' || *p > '9') return false;
        uint32_t prev = result;
        result = result * 10 + (*p - '0');
        if (result < prev) return false; /* overflow */
        p++;
    }
    *out = result;
    return true;
}

