static bool diag_check_lockout(void)
{
    if (g_session.state != AUTH_STATE_LOCKED_OUT) return false;

    uint32_t now = get_tick_sec();
    if ((now - g_session.lockout_start_tick) > DIAG_LOCKOUT_DURATION_SEC) {
        g_session.state = AUTH_STATE_LOCKED;
        g_session.failed_attempts = 0;
        diag_print_line("[INFO] Lockout period expired. Authentication available.");
        return false;
    }

    return true; /* Still locked out */
}

static bool diag_authenticate(const char *password)
{
    if (diag_check_lockout()) {
        uint32_t remaining = DIAG_LOCKOUT_DURATION_SEC -
                             (get_tick_sec() - g_session.lockout_start_tick);
        diag_uart_send_string("[DENIED] Account locked. Try again in ");
        diag_uart_send_uint32(remaining);
        diag_print_line(" seconds.");
        return false;
    }

    uint8_t input_hash[32];
    simple_hash(password, input_hash, sizeof(input_hash));

    if (secure_compare(input_hash, DIAG_AUTH_HASH, sizeof(DIAG_AUTH_HASH))) {
        g_session.state = AUTH_STATE_AUTHENTICATED;
        g_session.failed_attempts = 0;
        g_session.last_activity_tick = get_tick_sec();
        diag_print_line("[OK] Authenticated. Session active.");
        diag_uart_send_string("[INFO] Session timeout: ");
        diag_uart_send_uint32(DIAG_SESSION_TIMEOUT_SEC);
        diag_print_line(" seconds.");
        diag_audit_log_entry("AUTH_SUCCESS", 0);

        /* Clear hash from stack */
        memset(input_hash, 0, sizeof(input_hash));
        return true;
    }

    /* Clear hash from stack */
    memset(input_hash, 0, sizeof(input_hash));

    g_session.failed_attempts++;
    diag_uart_send_string("[DENIED] Authentication failed. Attempts: ");
    diag_uart_send_uint32(g_session.failed_attempts);
    diag_uart_send_char('/');
    diag_uart_send_uint32(DIAG_MAX_AUTH_FAILURES);
    diag_print_line("");

    diag_audit_log_entry("AUTH_FAILURE", 1);

    if (g_session.failed_attempts >= DIAG_MAX_AUTH_FAILURES) {
        g_session.state = AUTH_STATE_LOCKED_OUT;
        g_session.lockout_start_tick = get_tick_sec();
        diag_uart_send_string("[SECURITY] Max attempts exceeded. Locked for ");
        diag_uart_send_uint32(DIAG_LOCKOUT_DURATION_SEC);
        diag_print_line(" seconds.");
        diag_audit_log_entry("AUTH_LOCKOUT", 1);
    }

    return false;
}

