static void cmd_help(int argc, char *argv[])
{
    (void)argc; (void)argv;

    diag_print_line("=== Industrial IoT Sensor Diagnostic Console ===");
    diag_print_line("Available commands:");
    diag_print_line("");

    for (uint32_t i = 0; i < DIAG_CMD_COUNT; i++) {
        if (diag_commands[i].requires_auth && !diag_session_is_authenticated()) {
            continue; /* Don't show restricted commands to unauthenticated users */
        }
        diag_uart_send_string("  ");
        diag_uart_send_string(diag_commands[i].name);

        /* Pad to column */
        int pad = 16 - (int)strlen(diag_commands[i].name);
        while (pad-- > 0) diag_uart_send_char(' ');

        diag_print_line(diag_commands[i].help);
    }

    if (!diag_session_is_authenticated()) {
        diag_print_line("");
        diag_print_line("[INFO] Additional commands available after authentication.");
        diag_print_line("       Use 'auth <password>' to authenticate.");
    }
}

static void cmd_auth(int argc, char *argv[])
{
    if (argc < 2) {
        diag_print_line("Usage: auth <password>");
        return;
    }

    if (diag_session_is_authenticated()) {
        diag_print_line("[INFO] Already authenticated.");
        return;
    }

    diag_authenticate(argv[1]);

    /* Overwrite password in buffer to minimize exposure */
    memset(argv[1], 0, strlen(argv[1]));
}

