static void cmd_dump_memory(int argc, char *argv[])
{
    uint32_t addr, len = 256;

    if (!parse_hex(argv[1], &addr)) {
        diag_print_line("[ERROR] Invalid address. Use hex format: 0x20000000");
        return;
    }

    if (argc >= 3) {
        if (!parse_uint(argv[2], &len)) {
            diag_print_line("[ERROR] Invalid length.");
            return;
        }
    }

    /* Limit maximum dump size */
    if (len > 4096) {
        diag_print_line("[ERROR] Maximum dump size is 4096 bytes.");
        return;
    }

    /* Validate address range */
    if (!diag_is_address_safe(addr, len, true)) {
        diag_print_line("[DENIED] Address range not accessible.");
        diag_print_line("         Use 'regions' to see permitted memory ranges.");
        diag_audit_log_entry("dump_memory DENIED", 1);
        return;
    }

    diag_audit_log_entry("dump_memory", 0);

    diag_uart_send_string("Memory dump at 0x");
    diag_uart_send_hex(addr, 8);
    diag_uart_send_string(", ");
    diag_uart_send_uint32(len);
    diag_print_line(" bytes:");
    diag_print_line("----------------------------------------------------");

    volatile uint8_t *ptr = (volatile uint8_t *)addr;

    for (uint32_t i = 0; i < len; i += 16) {
        /* Address */
        diag_uart_send_string("0x");
        diag_uart_send_hex(addr + i, 8);
        diag_uart_send_string(": ");

        /* Hex bytes */
        uint32_t row_len = (len - i < 16) ? (len - i) : 16;
        for (uint32_t j = 0; j < row_len; j++) {
            diag_uart_send_hex8(ptr[i + j]);
            diag_uart_send_char(' ');
            if (j == 7) diag_uart_send_char(' ');
        }

        /* Pad if short row */
        for (uint32_t j = row_len; j < 16; j++) {
            diag_uart_send_string("   ");
            if (j == 7) diag_uart_send_char(' ');
        }

        diag_uart_send_string(" |");

        /* ASCII */
        for (uint32_t j = 0; j < row_len; j++) {
            char c = (char)ptr[i + j];
            diag_uart_send_char((c >= 0x20 && c <= 0x7E) ? c : '.');
        }

        diag_uart_send_char('|');
        diag_uart_send_string("\r\n");
    }

    diag_print_line("----------------------------------------------------");
}

static void cmd_read_flash(int argc, char *argv[])
{
    uint32_t offset, len = 256;

    if (!parse_hex(argv[1], &offset)) {
        diag_print_line("[ERROR] Invalid offset. Use hex format: 0x1000");
        return;
    }

    if (argc >= 3) {
        if (!parse_uint(argv[2], &len)) {
            diag_print_line("[ERROR] Invalid length.");
            return;
        }
    }

    uint32_t addr = FLASH_BASE_ADDR + offset;

    /* Validate within flash bounds */
    if (offset + len > FLASH_SIZE) {
        diag_print_line("[ERROR] Offset + length exceeds flash size.");
        return;
    }

    /* Limit maximum read size */
    if (len > 4096) {
        diag_print_line("[ERROR] Maximum read size is 4096 bytes.");
        return;
    }

    if (!diag_is_address_safe(addr, len, true)) {
        diag_print_line("[DENIED] Flash region not accessible.");
        diag_print_line("         Use 'regions' to see permitted memory ranges.");
        diag_audit_log_entry("read_flash DENIED", 1);
        return;
    }

    diag_audit_log_entry("read_flash", 0);

    diag_uart_send_string("Flash read at offset 0x");
    diag_uart_send_hex(offset, 8);
    diag_uart_send_string(" (addr 0x");
    diag_uart_send_hex(addr, 8);
    diag_uart_send_string("), ");
    diag_uart_send_uint32(len);
    diag_print_line(" bytes:");

    /* Reuse memory dump format */
    volatile uint8_t *ptr = (volatile uint8_t *)addr;
    for (uint32_t i = 0; i < len; i += 16) {
        diag_uart_send_string("0x");
        diag_uart_send_hex(addr + i, 8);
        diag_uart_send_string(": ");

        uint32_t row_len = (len - i < 16) ? (len - i) : 16;
        for (uint32_t j = 0; j < row_len; j++) {
            diag_uart_send_hex8(ptr[i + j]);
            diag_uart_send_char(' ');
        }
        diag_uart_send_string("\r\n");
    }
}

