static void cmd_audit_show(int argc, char *argv[])
{
    (void)argc; (void)argv;

    diag_print_line("=== Diagnostic Audit Log ===");

    diag_uart_send_string("Total entries logged: ");
    diag_uart_send_uint32(g_audit_log.total_entries);
    diag_print_line("");

    uint32_t count = g_audit_log.total_entries;
    if (count > AUDIT_LOG_MAX_ENTRIES) count = AUDIT_LOG_MAX_ENTRIES;

    if (count == 0) {
        diag_print_line("(no entries)");
        return;
    }

    diag_print_line("Time(s)    Result  Command");
    diag_print_line("---------- ------- --------------------------------");

    /* Show most recent entries (up to 20) */
    uint32_t start = 0;
    uint32_t show_count = count;
    if (show_count > 20) {
        start = show_count - 20;
        show_count = 20;
    }

    for (uint32_t i = start; i < start + show_count; i++) {
        uint32_t idx = i % AUDIT_LOG_MAX_ENTRIES;
        audit_entry_t *e = &g_audit_log.entries[idx];

        /* Timestamp */
        diag_uart_send_uint32(e->timestamp);
        int tpad = 11 - 1; /* rough padding */
        while (tpad-- > 0) diag_uart_send_char(' ');

        /* Result */
        switch (e->result) {
            case 0:  diag_uart_send_string("OK      "); break;
            case 1:  diag_uart_send_string("DENIED  "); break;
            case 2:  diag_uart_send_string("ERROR   "); break;
            default: diag_uart_send_string("???     "); break;
        }

        /* Command */
        diag_print_line((const char *)e->command);
    }

    diag_audit_log_entry("audit_show", 0);
}

