static void cmd_reboot(int argc, char *argv[])
{
    (void)argc; (void)argv;

    diag_audit_log_entry("reboot", 0);

    /* Disable JTAG before reboot */
    if (g_session.jtag_enabled_this_session) {
        diag_jtag_set_enabled(false);
    }

    diag_print_line("[INFO] Rebooting device...");

    /* Wait for UART to finish transmitting */
    while (!(USART2_SR & USART_SR_TC))
        ;

    /* ARM NVIC System Reset */
    #define AIRCR (*(volatile uint32_t *)0xE000ED0CUL)
    AIRCR = 0x05FA0004UL;

    /* Should not reach here */
    while (1) { }
}

/* ============================================================
 * Command Parser
 * ============================================================ */

static void diag_parse_and_execute(char *cmd_line)
{
    char *argv[DIAG_MAX_ARGS];
    int argc = 0;

    /* Skip leading whitespace */
    while (*cmd_line == ' ' || *cmd_line == '\t') cmd_line++;

    /* Empty line */
    if (*cmd_line == '\0') return;

    /* Tokenize */
    char *token = cmd_line;
    bool in_token = false;

    for (char *p = cmd_line; ; p++) {
        if (*p == ' ' || *p == '\t' || *p == '\0') {
            bool end = (*p == '\0');
            if (in_token) {
                *p = '\0';
                if (argc < DIAG_MAX_ARGS) {
                    argv[argc++] = token;
                }
                in_token = false;
            }
            if (end) break;
        } else {
            if (!in_token) {
                token = p;
                in_token = true;
            }
        }
    }

    if (argc == 0) return;

    /* Find and execute command */
    for (uint32_t i = 0; i < DIAG_CMD_COUNT; i++) {
        if (strcmp(argv[0], diag_commands[i].name) == 0) {

            /* Check authentication requirement */
            if (diag_commands[i].requires_auth && !diag_session_is_authenticated()) {
                diag_print_line("[DENIED] Authentication required. Use 'auth <password>'.");
                diag_audit_log_entry(argv[0], 1);
                return;
            }

            /* Check minimum arguments */
            if ((uint8_t)(argc - 1) < diag_commands[i].min_args) {
                diag_uart_send_string("[ERROR] Not enough arguments. Usage: ");
                diag_print_line(diag_commands[i].help);
                return;
            }

            /* Update session activity */
            if (diag_session_is_authenticated()) {
                diag_session_update_activity();
            }

            /* Execute */
            diag_commands[i].handler(argc, argv);
            return;
        }
    }

    diag_uart_send_string("[ERROR] Unknown command: '");
    diag_uart_send_string(argv[0]);
    diag_print_line("'. Type 'help' for available commands.");
}

/* ============================================================
 * Main Console Interface
 * ============================================================ */

void diag_console_init(void)
{
#if !DIAG_ENABLED
    return;
#endif

    /* Initialize UART */
    diag_uart_init();

    /* Initialize session (locked by default) */
    diag_session_init();

    /* Clear audit log */
    memset(&g_audit_log, 0, sizeof(g_audit_log));

    /* Disable JTAG by default in production */
#if !DIAG_JTAG_ALLOW_ENABLE
    diag_jtag_set_enabled(false);
#endif

    /* Clear command buffer */
    memset(g_cmd_buffer, 0, sizeof(g_cmd_buffer));
    g_cmd_index = 0;

    g_console_initialized = true;

    /* Print banner */
    diag_print_line("");
    diag_print_line("=============================================");
    diag_print_line("  Industrial IoT Sensor - Diagnostic Console");
    diag_print_line("  FW v2.4.1 | Secure Diag v1.0.0");
    diag_print_line("=============================================");
    diag_print_line("WARNING: Authorized access only.");
    diag_print_line("All commands are logged and audited.");
    diag_print_line("Type 'help' for available commands.");
    diag_print_line("Type 'auth <password>' to authenticate.");
    diag_print_line("");

    diag_audit_log_entry("CONSOLE_INIT", 0);

    /* Print prompt */
    diag_uart_send_string(DIAG_LOCKED_PROMPT);
}

/*
 * Call this from your main loop or a dedicated task.
 * Non-blocking: returns immediately if no data available.
 */
void diag_console_process(void)
{
#if !DIAG_ENABLED
    return;
#endif

    if (!g_console_initialized) return;

    /* Check session timeout */
    diag_session_check_timeout();

    /* Check for incoming character */
    if (!diag_uart_rx_ready()) return;

    char c = diag_uart_recv_char();

    /* Handle special characters */
    switch (c) {
        case '\r':
        case '\n':
            diag_uart_send_string("\r\n");
            g_cmd_buffer[g_cmd_index] = '\0';

            if (g_cmd_index > 0) {
                diag_parse_and_execute(g_cmd_buffer);
            }

            /* Reset buffer and show prompt */
            g_cmd_index = 0;
            memset(g_cmd_buffer, 0, sizeof(g_cmd_buffer));

            if (diag_session_is_authenticated()) {
                diag_uart_send_string(DIAG_PROMPT);
            } else {
                diag_uart_send_string(DIAG_LOCKED_PROMPT);
            }
            break;

        case '\b':
        case 0x7F: /* DEL */
            if (g_cmd_index > 0) {
                g_cmd_index--;
                diag_uart_send_string("\b \b");
            }
            break;

        case 0x03: /* Ctrl+C */
            diag_print_line("^C");
            g_cmd_index = 0;
            memset(g_cmd_buffer, 0, sizeof(g_cmd_buffer));
            if (diag_session_is_authenticated()) {
                diag_uart_send_string(DIAG_PROMPT);
            } else {
                diag_uart_send_string(DIAG_LOCKED_PROMPT);
            }
            break;

        default:
            /* Only accept printable characters */
            if (c >= 0x20 && c <= 0x7E) {
                if (g_cmd_index < DIAG_CMD_BUFFER_SIZE - 1) {
                    g_cmd_buffer[g_cmd_index++] = c;
                    diag_uart_send_char(c);
                }
            }
            break;
    }
}

